          />

          <button
            type="button"
            onClick={() => setShowTextPaste(!showTextPaste)}
            className="text-xs text-orange-600 font-bold flex items-center hover:underline"
          >
            {showTextPaste ? '▼ テキスト入力を閉じる' : '▶ サイトの情報をコピペして「無料」で反映させる'}
          </button>

          {showTextPaste && (
            <textarea
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-orange-500 outline-none bg-white text-gray-900 text-sm h-32"
              placeholder="サイトの物件概要などをここに貼り付けると、AIが正確に読み取ります（検索不要で無料）"
              value={formData.referenceText || ''}
