import { GoogleGenAI, Part, GenerateContentResponse } from "@google/genai";
import { FLATTENED_FORBIDDEN_WORDS } from "../constants";

const convertFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = error => reject(error);
  });
};

export const generatePropertyDescriptionStream = async (
  propertyName: string,
  address: string,
  pdfFile: File | null,
  referenceUrl: string,
  referenceText: string | undefined,
  useSearch: boolean,
  onChunk: (text: string) => void,
  buildingAge?: string,
  totalUnits?: string
): Promise<{ fullText: string; groundingUrls: string[] }> => {

  // Vercel等の本番環境とVite開発環境の両方に対応
  const apiKey = process.env.API_KEY || (import.meta as any).env?.VITE_GEMINI_API_KEY;

  if (!apiKey) {
    throw new Error("APIキーが設定されていません。VercelのEnvironment Variables設定を確認してください。");
  }

  const ai = new GoogleGenAI({ apiKey: apiKey });

  let base64Pdf: string | null = null;
  if (pdfFile) {
    base64Pdf = await convertFileToBase64(pdfFile);
  }

  const forbiddenListString = FLATTENED_FORBIDDEN_WORDS.join(', ');

  const systemInstruction = `
あなたは不動産広告の規約遵守と正確性を極めたプロのコピーライターです。

【情報ソースの優先順位】
1. ユーザーが貼り付けたWebサイトのテキスト内容 (${referenceText ? 'あり' : 'なし'})
2. ユーザー入力スペック (築年: ${buildingAge || '未指定'}, 戸数: ${totalUnits || '未指定'})
3. 添付PDFデータ
4. Google検索の結果 (※検索ツールが有効な場合のみ)

【文章作成の絶対ルール】
・ユーザーが「Webサイトのテキスト内容」を提供している場合、その情報を「最新の正解」として扱い、生成に反映させてください。
・物件名「${propertyName}」を必ず含める。
・文字数は450〜550文字程度で、読みやすく段落を分けてください。
・不動産公正競争規約に抵触する禁止用語（${forbiddenListString}）は絶対に使用しないでください。
・「徒歩◯分」などの数値は、提供されたソースに記載がある場合のみ使用し、不明な場合は住所 (${address}) からの距離を推測で書かないでください。
`;

  let userPrompt = `
【物件基本情報】
物件名: ${propertyName}
住所: ${address}
${buildingAge ? `築年数: ${buildingAge}\n` : ''}${totalUnits ? `総戸数: ${totalUnits}\n` : ''}

${referenceText ? `【Webサイトからコピーされた最新情報（優先参照）】\n${referenceText}\n` : ''}
${referenceUrl ? `【関連URL（検索ツール用）】\n${referenceUrl}\n` : ''}

指示:
上記の情報に基づき、ポータルサイト掲載用の魅力的な物件紹介文を作成してください。
`;

  try {
    const parts: Part[] = [{ text: userPrompt }];
    if (base64Pdf) {
      parts.push({
        inlineData: {
          mimeType: 'application/pdf',
          data: base64Pdf
        }
      });
    }

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-pro-preview',
      contents: [{ role: 'user', parts: parts }],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.1, 
        tools: useSearch ? [{ googleSearch: {} }] : []
      }
    });

    let fullText = "";
    let groundingUrls: string[] = [];

    for await (const chunk of responseStream) {
      const textChunk = chunk.text;
      if (textChunk) {
        fullText += textChunk;
        onChunk(fullText);
      }

      const chunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach(c => {
          if (c.web?.uri) groundingUrls.push(c.web.uri);
        });
      }
    }

    return { 
      fullText, 
      groundingUrls: [...new Set(groundingUrls)] 
    };

  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error("生成中にエラーが発生しました。詳細はログを確認してください。");
  }
};

