// 実際のAPI呼び出し時にはエラーが発生しますが、UIのレンダリングは継続されます。
export const supabase = createClient(
  SUPABASE_URL || 'https://placeholder-project.supabase.co',
  SUPABASE_ANON_KEY || 'placeholder-anon-key'
);

