        });
      }
    }

    return { 
      fullText, 
      groundingUrls: [...new Set(groundingUrls)] 
    };

  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("AI生成中にエラーが発生しました。");
  }
};

