import { createClient } from '@supabase/supabase-js';

// 環境変数を広範囲から検索する関数
const getEnvVar = (key: string): string | undefined => {
  const keysToTry = [
    key,                                  // VITE_SUPABASE_URL
    key.replace('VITE_', ''),             // SUPABASE_URL
    `REACT_APP_${key.replace('VITE_', '')}` // REACT_APP_SUPABASE_URL
  ];

  // 1. process.env (Node/Vercel)
  if (typeof process !== 'undefined' && process.env) {
    for (const k of keysToTry) {
      if (process.env[k]) return process.env[k];
    }
  }

  // 2. import.meta.env (Vite)
  try {
    const metaEnv = (import.meta as any).env;
    if (metaEnv) {
      for (const k of keysToTry) {
        if (metaEnv[k]) return metaEnv[k];
      }
    }
  } catch (e) {}

  // 3. window (グローバル)
  const win = window as any;
  for (const k of keysToTry) {
    if (win[k]) return win[k];
    if (win.__env__ && win.__env__[k]) return win.__env__[k];
  }

  return undefined;
};

