import { GoogleGenAI, Part } from "@google/genai";
import { FLATTENED_FORBIDDEN_WORDS } from "../constants";

const convertFileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = error => reject(error);
  });
};

const getApiKey = (): string | undefined => {
  if (typeof process !== 'undefined' && process.env) {
    if (process.env.API_KEY) return process.env.API_KEY;
    if (process.env.VITE_GEMINI_API_KEY) return process.env.VITE_GEMINI_API_KEY;
  }
  return undefined;
};

// APIキーがない場合のデモ用シミュレーター（爆速返答）
const simulateStream = async (onChunk: (text: string) => void) => {
  const demoText = `【キャッチコピー案】
1. 圧倒的開放感！南青山を一望する、ミルズ至高のデザイナーズ邸宅。
2. 駅徒歩3分の奇跡。利便性と静寂が響き合う、次世代の暮らし。
